class Solution:
    def peopleIndexes(self, favoriteCompanies: list) -> list:
        sets = [set(fc) for fc in favoriteCompanies]
        result = []
        for i in range(len(sets)):
            dominated = False
            for j in range(len(sets)):
                if i != j and sets[i].issubset(sets[j]):
                    dominated = True
                    break
            if not dominated:
                result.append(i)
        return result

solutions.javascript:
var peopleIndexes = function(favoriteCompanies) {
    const sets = favoriteCompanies.map(fc => new Set(fc));
    const result = [];
    for (let i = 0; i < sets.length; i++) {
        let dominated = false;
        for (let j = 0; j < sets.length; j++) {
            if (i === j) continue;
            let isSubset = true;
            for (const c of sets[i]) {
                if (!sets[j].has(c)) { isSubset = false; break; }
            }
            if (isSubset) { dominated = true; break; }
        }
        if (!dominated) result.push(i);
    }
    return result;
};
